module block_mem_generator
   (douta,
    addra,
    clka,
    dina,
    wea);

  output reg [11:0] douta;
  input [13:0] addra;
  input clka;
  input [11:0] dina;
  input wea;

  reg [11:0] mem [0:16383];

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clka or posedge dbg_halt) begin
    if(wea) begin
      mem[addra] <= dina;
    end else begin
      douta <= mem[addra];
    end
  end
endmodule
